#!/bin/bash

WORKDIR=/home/liunyw/project/howler_monkey

cd ${WORKDIR}/gene_loss && mkdir plot_geneInactivateMutation && cd plot_geneInactivateMutation


for spe in $(cat /home/liunyw/project/howler_monkey/assemblyStats/futher_analysis_TOGA.txt);
	do
		${WORKDIR}/software/TOGA/supply/mut_index.py ${WORKDIR}/TOGA_data/human_hg38_data/${spe}/geneInactivatingMutations.tsv hg38_${spe##*__}_inact_mut_data.hdf5
		grep -E 'ENSG00000112695|ENSG00000132517|ENSG00000134216|ENSG00000134812|ENSG00000141086|ENSG00000142789|ENSG00000153002|ENSG00000158516|ENSG00000163515|ENSG00000163751|ENSG00000164822|ENSG00000172955|ENSG00000179914|ENSG00000187021|ENSG00000219073|ENSG00000226784|ENSG00000257743|ENSG00000259823|ENSG00000101440|ENSG00000258839|ENSG00000205277|ENSG00000181143|ENSG00000130957|ENSG00000165140' ${WORKDIR}/software/TOGA/TOGAInput/human_hg38/toga.isoforms.tsv > hg38_${spe##*__}_isoforms.txt;
		for gene in ENSG00000112695 ENSG00000132517 ENSG00000134216 ENSG00000134812 ENSG00000141086 ENSG00000142789 ENSG00000153002 ENSG00000158516 ENSG00000163515 ENSG00000163751 ENSG00000164822 ENSG00000172955 ENSG00000179914 ENSG00000187021 ENSG00000219073 ENSG00000226784 ENSG00000257743 ENSG00000259823 ENSG00000101440 ENSG00000258839 ENSG00000205277 ENSG00000181143 ENSG00000130957 ENSG00000165140; do ${WORKDIR}/software/TOGA/supply/plot_mutations.py ${WORKDIR}/software/TOGA/TOGAInput/human_hg38/toga.transcripts.bed hg38_${spe##*__}_inact_mut_data.hdf5 ${gene} hg38_${spe##*__}_${gene}.svg -i hg38_${spe##*__}_isoforms.txt; done
	done
